package Welcome;

public class relationaloperators {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int a=10;
		int b =20;
		System.out.println(a<b);
		System.out.println(a>b);
		System.out.println(a>=b);
		
		
		int x=10;
		x+=1;
		System.out.println(x);
		x-=1;
		System.out.println(x);
		
		

	}

}
